<template>
  <div class="navigation" :class="{ 'dark-theme': currentTheme === 'dark' }">
    
    <div class="search-container">
      <div class="search-bar">
        <el-input
          v-model="localSearchQuery"
          placeholder=">"
          clearable
          class="search-input"
          @keydown.enter="performSearch"
        >
          <template #prepend>
            <el-select 
              v-model="searchMode" 
              class="search-mode" 
              style="width: 100px"
              :popper-class="currentTheme === 'dark' ? 'dark-dropdown' : ''"
            >
              <el-option label="Google" value="Google"></el-option>
              <el-option label="Bing" value="Bing"></el-option>
              <el-option label="Sogou" value="Sogou"></el-option>
              <el-option label="Baidu" value="Baidu"></el-option>
            </el-select>
          </template>
        </el-input>

        <el-button class="search-button" type="default" @click="performSearch">搜索</el-button>
      </div>
    </div>

    <div class="pagination-container pagination-top" v-if="filteredCategories.length > 0">
      <el-pagination
        v-model:current-page="currentPage"
        :page-size="pageSize"
        :total="filteredCategories.length"
        layout="prev, pager, next"
        @current-change="handlePageChange"
        background
      />
    </div>


    <div v-if="localSearchQuery && filteredCategories.length === 0" class="no-result-wrapper">
      <el-empty description="未找到相关内容" :image-size="200"></el-empty>
    </div>

    <div v-for="category in paginatedCategories" :key="category.name" class="category" :data-category="category.name">
      <h2 class="category-title">
        <span style="display: inline-flex; margin-right: 4px;">{{ category.emoji }}</span>
        {{ category.name }}
        <span class="category-count">{{ getCategoryCount(category) }}</span>
      </h2>

      <div class="links-container">
        <template v-if="category.subCategories && category.subCategories.length > 0">
          <div v-for="sub in category.subCategories" :key="sub.name" class="sub-category-group">
            <h3 class="subcategory-title">
              <span class="decoration">#</span> {{ sub.name }}
            </h3>
            <ul>
              <li v-for="link in sub.links" :key="link.name">
                <el-popover
                  placement="top"
                  :width="280"
                  trigger="hover"
                  :popper-class="currentTheme === 'dark' ? 'dark-popover' : ''"
                >
                  <template #reference>
                    <a :href="link.url" target="_blank" rel="noopener noreferrer"> 
                      <el-button 
                        :type="currentTheme === 'dark' ? 'primary' : ''" 
                        :plain="currentTheme !== 'dark'"
                        class="link-button"
                      >
                        <img 
                          v-if="getFaviconUrl(link.url)" 
                          :src="getFaviconUrl(link.url)" 
                          class="favicon" 
                          @error="handleImageError($event, link.url)" 
                        />
                        <span class="link-text">{{ link.name }}</span>
                        <template v-if="link.tag || (link.tags && link.tags.length)">
                          <el-tag v-for="(t, idx) in normalizeTags(link)" :key="idx" size="small" :type="getTagType(t)" class="link-mini-tag" effect="plain">{{ t }}</el-tag>
                        </template>
                      </el-button>
                    </a>
                  </template>

                  <div class="popover-content" :class="{ 'dark-content': currentTheme === 'dark' }">
                    <div class="pop-header">
                      <span class="pop-title">>> {{ link.name }}</span>
                      <span v-if="currentTheme === 'dark'" class="pop-status">ONLINE</span>
                    </div>
                    <div class="pop-desc">
                        {{ link.description || 'No description available.' }}
                    </div>
                    <div class="pop-footer">
                      <span class="pop-url">TARGET: {{ formatUrl(link.url) }}</span>
                      <button class="dark-btn" @click.stop="copyLink(link.url)">[ COPY ]</button>
                    </div>
                  </div>
                </el-popover>
                </li>
            </ul>
          </div>
        </template>

        <ul v-else>
          <li v-for="link in category.links" :key="link.name">
             <el-popover
                  placement="top"
                  :width="280"
                  trigger="hover"
                  :popper-class="currentTheme === 'dark' ? 'dark-popover' : ''"
                >
                  <template #reference>
                    <a :href="link.url" target="_blank" rel="noopener noreferrer"> 
                      <el-button 
                        :type="currentTheme === 'dark' ? 'primary' : ''" 
                        :plain="currentTheme !== 'dark'"
                        class="link-button"
                      >
                        <img 
                          v-if="getFaviconUrl(link.url)" 
                          :src="getFaviconUrl(link.url)" 
                          class="favicon" 
                          @error="handleImageError($event, link.url)" 
                        />
                        <span class="link-text">{{ link.name }}</span>
                        <template v-if="link.tag || (link.tags && link.tags.length)">
                          <el-tag v-for="(t, idx) in normalizeTags(link)" :key="idx" size="small" :type="getTagType(t)" class="link-mini-tag" effect="plain">{{ t }}</el-tag>
                        </template>
                      </el-button>
                    </a>
                  </template>

                  <div class="popover-content" :class="{ 'dark-content': currentTheme === 'dark' }">
                    <div class="pop-header">
                      <span class="pop-title">>> {{ link.name }}</span>
                      <span v-if="currentTheme === 'dark'" class="pop-status">ONLINE</span>
                    </div>
                    <div class="pop-desc">
                        {{ link.description || 'No description available.' }}
                    </div>
                    <div class="pop-footer">
                      <span class="pop-url">TARGET: {{ formatUrl(link.url) }}</span>
                      <button class="dark-btn" @click.stop="copyLink(link.url)">[ COPY ]</button>
                    </div>
                  </div>
                </el-popover>
                </li>
        </ul>
      </div>
    </div>

    <div class="pagination-container" v-if="filteredCategories.length > 0">
      <el-pagination
        v-model:current-page="currentPage"
        :page-size="pageSize"
        :total="filteredCategories.length"
        layout="prev, pager, next"
        @current-change="handlePageChange"
        background
      />
    </div>
  </div>
</template>

<script>
// 导入Element Plus的消息提示组件
import { ElMessage } from 'element-plus'; 
// 导入拼音工具函数，用于支持拼音首字母搜索
import { getPinyinInitials } from '../utils/pinyin.js'; 

// 导航链接组件定义
export default {
  name: 'NavigationLinks',
  // 组件属性定义
  props: {
    categories: { type: Array, required: true }, // 导航分类数据
    currentTheme: { type: String, required: true }, // 当前主题（light/dark）
    targetCategory: { type: String, default: '' }, // 目标分类（用于滚动定位）
  },
  // 组件数据
  data() {
    return {
      currentPage: 1, // 当前页码
      pageSize: 15, // 每页显示分类数量
      localSearchQuery: '', // 本地搜索关键词
      searchMode: 'Google', // 默认搜索引擎
      resizeTimer: null, // 窗口 resize 防抖定时器
      searchDebounceTimer: null, // 搜索防抖计时器

      // 打字机效果数据（搜索框）
      typingText: '', // 当前打字文本
      typewriterPhrases: ['请输入关键词搜索...', '请输入关键词搜索...', '请输入关键词搜索...', '请输入关键词搜索...'],
      phraseIndex: 0, // 当前短语索引
      charIndex: 0, // 当前字符索引
      isDeleting: false, // 是否正在删除文本
      typeSpeed: 100, // 打字速度（毫秒/字符）
      deleteSpeed: 50, // 删除速度（毫秒/字符）
      pauseTime: 2000, // 暂停时间（毫秒）
      typewriterTimer: null, // 打字机定时器


    };
  },
  // 组件挂载后执行
  mounted() {
    // 添加窗口 resize 事件监听
    window.addEventListener('resize', this.handleResize);
    // 启动搜索框打字机效果
    this.startTypewriter();
  },
  // 组件卸载前执行
  beforeUnmount() {
    // 移除窗口 resize 事件监听
    window.removeEventListener('resize', this.handleResize);
    // 清理打字机定时器
    if (this.typewriterTimer) clearTimeout(this.typewriterTimer);
    // 清理搜索防抖计时器
    if (this.searchDebounceTimer) clearTimeout(this.searchDebounceTimer);
  },
  // 计算属性
  computed: {
      // 过滤后的分类数据：根据搜索关键词筛选分类和链接
      filteredCategories() {
        const query = this.localSearchQuery.trim().toLowerCase();
        // 如果没有搜索关键词，返回所有分类
        if (!query) return this.categories;
        
        // 判断是否为URL搜索
        const isUrl = query.startsWith('http') || query.startsWith('www.') || query.includes('.');
        const filtered = [];
        
        // 预计算拼音搜索条件
        const isPinyinQuery = /^[a-z]+$/.test(query);
        
        // 构建搜索函数，避免重复计算
        const shouldIncludeLink = (link) => {
          // URL搜索模式
          if (isUrl) {
            return link.url.toLowerCase().includes(query);
          }
          
          // 普通文本搜索：名称、描述、URL
          const linkName = link.name.toLowerCase();
          const linkDesc = (link.description || '').toLowerCase();
          const linkUrl = link.url.toLowerCase();
          
          // 完全匹配优先
          if (linkName.includes(query) || linkDesc.includes(query) || linkUrl.includes(query)) {
            return true;
          }
          
          // 拼音首字母搜索
          if (isPinyinQuery && linkName) {
            const pinyinInitials = getPinyinInitials(link.name).toLowerCase();
            return pinyinInitials.includes(query);
          }
          
          return false;
        };
        
        // 使用for循环代替map和filter，减少中间对象创建
        for (let i = 0; i < this.categories.length; i++) {
          const category = this.categories[i];
          let hasMatchingLinks = false;
          let processedCategory = null;
          
          if (category.subCategories && category.subCategories.length > 0) {
            const filteredSubs = [];
            
            for (let j = 0; j < category.subCategories.length; j++) {
              const sub = category.subCategories[j];
              const links = sub.links || [];
              const filteredLinks = [];
              
              for (let k = 0; k < links.length; k++) {
                const link = links[k];
                if (shouldIncludeLink(link)) {
                  filteredLinks.push(link);
                }
              }
              
              if (filteredLinks.length > 0) {
                filteredSubs.push({ ...sub, links: filteredLinks });
                hasMatchingLinks = true;
              }
            }
            
            if (hasMatchingLinks) {
              processedCategory = { ...category, subCategories: filteredSubs };
            }
          } else if (category.links && category.links.length > 0) {
            const filteredLinks = [];
            
            for (let k = 0; k < category.links.length; k++) {
              const link = category.links[k];
              if (shouldIncludeLink(link)) {
                filteredLinks.push(link);
              }
            }
            
            if (filteredLinks.length > 0) {
              processedCategory = { ...category, links: filteredLinks };
              hasMatchingLinks = true;
            }
          }
          
          if (hasMatchingLinks) {
            filtered.push(processedCategory);
          }
        }
        
        return filtered;
      },
    // 分页后的分类数据：根据当前页码和每页大小切片过滤后的数据
    paginatedCategories() {
      const start = (this.currentPage - 1) * this.pageSize;
      return this.filteredCategories.slice(start, start + this.pageSize);
    }
  },
  // 监听器
  watch: {
    // 监听搜索关键词变化：添加防抖处理
    localSearchQuery: {
      handler() {
        // 清除旧的防抖计时器
        if (this.searchDebounceTimer) {
          clearTimeout(this.searchDebounceTimer);
        }
        // 设置新的防抖计时器
        this.searchDebounceTimer = setTimeout(() => {
          // 搜索时重置到第一页
          this.currentPage = 1;
        }, 30); // 30ms防抖延迟
      },
      immediate: true // 立即执行
    },
    // 监听目标分类变化：滚动到指定分类
    targetCategory: {
      handler(newVal) { this.scrollToCategory(newVal); },
      immediate: true
    }
  },
  // 方法
  methods: {
    // 复制链接功能
    async copyLink(url) {
      try {
        // 使用Clipboard API复制链接
        await navigator.clipboard.writeText(url);
        // 显示复制成功消息
        ElMessage({
          message: this.currentTheme === 'dark' ? '>> SYSTEM: URL COPIED TO CLIPBOARD.' : '链接已复制到剪贴板',
          type: 'success',
          customClass: this.currentTheme === 'dark' ? 'dark-message' : '',
          duration: 2000,
        });
      } catch (err) {
        // 复制失败处理
        ElMessage.error('Copy Failed');
      }
    },

    formatUrl(url) {
      try {
        return new URL(url).hostname;
      } catch {
        return 'UNKNOWN HOST';
      }
    },

    startTypewriter() {
          const currentPhrase = this.typewriterPhrases[this.phraseIndex];
          if (this.isDeleting) {
            this.typingText = currentPhrase.substring(0, this.charIndex - 1);
            this.charIndex--;
          } else {
            this.typingText = currentPhrase.substring(0, this.charIndex + 1);
            this.charIndex++;
          }
          let nextSpeed = this.typeSpeed;
          if (this.isDeleting) nextSpeed = this.deleteSpeed;

          if (!this.isDeleting && this.charIndex === currentPhrase.length) {
            nextSpeed = this.pauseTime;
            this.isDeleting = true;
          } else if (this.isDeleting && this.charIndex === 0) {
            this.isDeleting = false;
            this.phraseIndex = (this.phraseIndex + 1) % this.typewriterPhrases.length;
            nextSpeed = 500;
          }
          this.typewriterTimer = setTimeout(() => {
            this.startTypewriter();
          }, nextSpeed);
        },
    handleResize() {
      if (this.resizeTimer) clearTimeout(this.resizeTimer);
      this.resizeTimer = setTimeout(() => {
        // 处理窗口大小变化
      }, 200);
    },
    getCategoryCount(category) {
      if (category.subCategories && category.subCategories.length > 0) {
        return category.subCategories.reduce((acc, sub) => acc + (sub.links ? sub.links.length : 0), 0);
      }
      return category.links ? category.links.length : 0;
    },
    normalizeTags(link) {
      if (Array.isArray(link.tags)) return link.tags;
      if (typeof link.tag === 'string' && link.tag.trim()) return [link.tag.trim()];
      return [];
    },
    getTagType(tag) {
      const t = (tag || '').trim();
      if (['开源', 'Open Source', 'OSS'].includes(t)) return 'success';
      if (['免费', 'Free'].includes(t)) return 'info';
      if (['收费', '付费', 'Pro', '订阅'].includes(t)) return 'warning';
      if (['内测', 'Beta'].includes(t)) return 'danger';
      return null;
    },
    getFaviconUrl(url) {
      try {
        const domain = new URL(url).hostname;
        return `https://favicon.yandex.net/favicon/${domain}`;
      } catch {
        return '/default-favicon.ico';
      }
    },
    handleImageError(event, url) {
      const img = event.target;
      try {
        const domain = new URL(url).hostname;
        if (img.src.includes('yandex.net')) {
          img.src = `https://www.google.com/s2/favicons?domain=${domain}&sz=32`;
        } else { img.src = '/default-favicon.ico'; }
      } catch (e) { img.style.display = 'none'; }
    },
    // 执行搜索：根据选择的搜索引擎打开搜索结果
    performSearch() {
      const query = this.localSearchQuery.trim();
      if (!query) return;
      
      // 搜索引擎URL映射
      const map = {
        Google: `https://www.google.com/search?q=`,
        Bing: `https://www.bing.com/search?q=`,
        Baidu: `https://www.baidu.com/s?wd=`,
        Sogou: `https://www.sogou.com/web?query=`
      };
      
      // 获取搜索引擎URL前缀
      const prefix = map[this.searchMode] || map.Google;
      // 打开新窗口搜索
      window.open(prefix + encodeURIComponent(query), '_blank');
    },
    handlePageChange(page) { this.currentPage = page; },
    scrollToCategory(categoryName) {
      if (!categoryName) return;
      const idx = this.filteredCategories.findIndex(c => c.name === categoryName);
      if (idx === -1) return;
      const targetPage = Math.floor(idx / this.pageSize) + 1;
      if (this.currentPage !== targetPage) this.currentPage = targetPage;
      this.$nextTick(() => {
        const el = document.querySelector(`[data-category="${categoryName}"]`);
        if (el) el.scrollIntoView({ behavior: 'auto', block: 'start' });
      });
    }
  }
}
</script>

