<template>
  <div>
    <div 
      v-if="isMobile && isMobileMenuVisible" 
      class="mobile-overlay"
      @click="toggleMenu"
    ></div>

    <div class="mobile-toggle" :class="{ 'mobile-toggle-dark': isDarkTheme }" @click="toggleMenu">
      <el-icon size="24">
        <Expand v-if="isMobile ? !isMobileMenuVisible : isCollapsed" />
        <Fold v-else />
      </el-icon>
    </div>
    
    <div class="side-navigation" 
      :class="{
        'side-navigation-dark': isDarkTheme,
        'mobile-visible': isMobileMenuVisible,
        'collapsed': !isMobile && isCollapsed
      }">

      <el-button class="collapse-btn" @click="toggleCollapse" v-if="!isMobile">
        <el-icon>
          <Fold v-if="!isCollapsed" />
          <Expand v-else />
        </el-icon>
      </el-button>

      <div class="unified-control-panel">
        <el-button 
          class="scroll-bottom-btn"
          @click="scrollToBottom"
          title="滚动到底部"
        >
          <el-icon><ArrowDownBold /></el-icon>
        </el-button>

        <el-input
          v-model="searchText"
          placeholder="搜索分类"
          clearable
          prefix-icon="Search"
          @input="handleSearchInput"
          v-show="!isCollapsed"
          class="search-input"
        />

        <div :class="['statistics-info', { collapsed: isCollapsed }]"> 
          <span>分类: {{ filteredCategories.length }}</span>
          <span>链接: {{ totalLinksCount }}</span>
        </div>
      </div>

      <div class="side-nav-content" ref="scrollContainer">
        <el-menu
          :default-active="activeIndex"
          class="side-nav-menu"
          ref="sideMenu"
          @select="handleSelect"
          :collapse="isCollapsed" 
          :collapse-transition="false"
        >
          <div class="groups-container">
            <div 
              v-for="(groupItems, groupName) in groupedCategories" 
              :key="groupName"
              class="category-group-box"
              :class="{ 'group-box-collapsed': isCollapsed }"
            >
              <div v-if="!isCollapsed && groupName !== 'default_ungrouped'" class="group-title">
                {{ groupName }}
              </div>

              <div class="menu-grid" :class="{ 'menu-grid-collapsed': isCollapsed }">
                <el-menu-item 
                  v-for="category in groupItems" 
                  :key="category.name" 
                  :index="category.name"
                  :class="{ 'is-active': activeIndex === category.name }"
                >
                  <span v-if="category.emoji" class="emoji-icon">{{ category.emoji }}</span>
                  <el-icon v-else>
                    <component :is="category.icon || 'Folder'" />
                  </el-icon>
                  
                  <template #title>
                    <span class="category-name">{{ category.name }}</span>
                    <span class="item-count">{{ getCategoryCount(category) }}</span>
                  </template>
                </el-menu-item>
              </div>
            </div>

            <div v-if="filteredCategories.length === 0" class="empty-state">
              <el-icon size="20" color="#909399"><WarnTriangleFilled /></el-icon>
              <p>无结果</p>
            </div>

          </div>
        </el-menu>
      </div>

      <div class="back-to-top-wrapper">
        <el-button 
          class="back-to-top-btn"
          @click="scrollToTop"
          title="返回顶部"
        >
          <el-icon><ArrowUpBold /></el-icon>
        </el-button>
      </div>
    </div>
  </div>
</template>

<script>
import { Folder, Expand, Fold, Monitor, Search, ArrowUpBold, ArrowDownBold, WarnTriangleFilled } from '@element-plus/icons-vue'
import { navData } from "../nav-data.js"
import * as ElementPlusIcons from '@element-plus/icons-vue'
import { nextTick } from 'vue'
import { getPinyinInitials } from "../utils/pinyin.js"

export default {
  name: 'SideNavigation',
  components: {
    Folder, Expand, Fold, Monitor, Search, ArrowUpBold, ArrowDownBold, WarnTriangleFilled,
    ...ElementPlusIcons
  },
  props: {
    isDarkTheme: { type: Boolean, default: false },
    isCollapsed: { type: Boolean, default: false },
    isMobileMenuVisible: { type: Boolean, default: false }
  },
  data() {
    return {
      activeIndex: '',
      categories: navData,
      searchText: '',
      filteredCategories: navData,
      isMobile: window.innerWidth <= 768,
      resizeTimer: null,
      searchTimer: null
    }
  },
  computed: {
    totalLinksCount() {
      return this.filteredCategories.reduce((total, category) => total + this.getCategoryCount(category), 0);
    },
    groupedCategories() {
      const groups = {};
      const otherCategory = [];
      this.filteredCategories.forEach(cat => {
        const groupName = cat.group || '其他分类'; 
        if (groupName === '其他分类') otherCategory.push(cat);
        else {
          if (!groups[groupName]) groups[groupName] = [];
          groups[groupName].push(cat);
        }
      });
      const result = {};
      Object.keys(groups).forEach(name => result[name] = groups[name]);
      if (otherCategory.length) result['其他分类'] = otherCategory;
      return result;
    }
  },
  beforeUnmount() {
    window.removeEventListener('resize', this.handleResize);
  },
  mounted() {
    this.handleResize();
    window.addEventListener('resize', this.handleResize);
  },
  methods: {
    handleResize() {
      if (this.resizeTimer) clearTimeout(this.resizeTimer);
      this.resizeTimer = setTimeout(() => {
        this.isMobile = window.innerWidth <= 768;
        if (!this.isMobile && this.isMobileMenuVisible) {
          this.$emit('update:isMobileMenuVisible', false);
        }
      }, 100);
    },
    getCategoryCount(category) {
      if (category.subCategories && category.subCategories.length) {
        return category.subCategories.reduce((acc, sub) => acc + (sub.links ? sub.links.length : 0), 0);
      }
      return category.links ? category.links.length : 0;
    },
    
    handleSearchInput() {
      if (this.searchTimer) clearTimeout(this.searchTimer);
      this.searchTimer = setTimeout(() => this.filterCategories(), 300);
    },
    filterCategories() {
      if (!this.searchText) {
        this.filteredCategories = this.categories;
        return;
      }
      const searchLower = this.searchText.trim().toLowerCase();
      this.filteredCategories = this.categories.filter(category => {
        const name = category.name.toLowerCase();
        const py = getPinyinInitials(category.name).toLowerCase();
        const grp = (category.group || '').toLowerCase();
        const matchSub = category.subCategories ? category.subCategories.some(s => s.name.toLowerCase().includes(searchLower)) : false;
        return name.includes(searchLower) || py.includes(searchLower) || grp.includes(searchLower) || matchSub;
      });
    },
    handleSelect(index) {
      this.activeIndex = index;
      this.$emit('category-selected', index);
      this.$emit('clear-top-search');
      if (this.isMobile) this.$emit('update:isMobileMenuVisible', false);
    },
    toggleMenu() {
      if (this.isMobile) {
        this.$emit('update:isMobileMenuVisible', !this.isMobileMenuVisible);
        nextTick(() => window.dispatchEvent(new Event('resize')));
      } else {
        this.$emit('update:isCollapsed', !this.isCollapsed);
      }
    },
    scrollToTop() {
      this.$refs.scrollContainer?.scrollTo({ top: 0, behavior: 'auto' });
    },
    scrollToBottom() {
      this.$refs.scrollContainer?.scrollTo({ top: this.$refs.scrollContainer.scrollHeight, behavior: 'auto' });
    },
    toggleCollapse() {
      this.$emit('update:isCollapsed', !this.isCollapsed);
    }
  }
}
</script>

